import { RuleTester } from 'eslint';
import tseslint from 'typescript-eslint';
import { noBrowserDialogs } from "../../rules/no-browser-dialogs.js";
import { languageOptions } from "../../runtime.js";
const ruleTester = new RuleTester({
    languageOptions: {
        ...languageOptions,
        parserOptions: {
            ecmaVersion: 'latest',
            sourceType: 'module',
            ecmaFeatures: {
                jsx: true,
            },
        },
    },
});
// Separate tester for TypeScript code
const tsRuleTester = new RuleTester({
    languageOptions: {
        ...languageOptions,
        parser: tseslint.parser,
        parserOptions: {
            ecmaVersion: 'latest',
            sourceType: 'module',
        },
    },
});
describe('no-browser-dialogs', () => {
    // Main test suite with JavaScript code
    ruleTester.run('no-browser-dialogs', noBrowserDialogs, {
        valid: [
            {
                name: 'allows dialog methods on other objects',
                code: `
          const custom = { alert: () => {}, confirm: () => {}, prompt: () => {} };
          custom.alert('msg');
          custom.confirm('msg');
          custom.prompt('msg');
        `,
            },
            {
                name: 'allows dialog methods as function parameters',
                code: `
          function process(alert, confirm, prompt) {
            alert('msg');
            confirm('msg');
            prompt('msg');
          }
        `,
            },
            {
                name: 'allows locally declared dialog functions',
                code: `
          const alert = (msg) => actions.addAlert(msg);
          const confirm = (msg) => showModal(msg);
          const prompt = (msg) => showInputModal(msg);
          alert('msg');
          confirm('msg');
          prompt('msg');
        `,
            },
            {
                name: 'allows destructured dialog methods from objects',
                code: `
          const { alert, confirm, prompt } = customDialogs;
          alert('msg');
          confirm('msg');
          prompt('msg');
        `,
            },
            {
                name: 'ignores dialog methods in comments and strings',
                code: `
          // Use alert() to show messages
          const msg = 'Use confirm() for decisions';
          /* prompt() gets user input */
          actions.addAlert('Hello');
        `,
            },
        ],
        invalid: [
            {
                name: 'reports errors for global calls to dialog APIs',
                code: `
          alert('Attention');
          confirm('Are you sure?');
          prompt('Enter your name:');
        `,
                errors: [
                    {
                        messageId: 'nativeAlert',
                    },
                    {
                        messageId: 'nativeConfirm',
                    },
                    {
                        messageId: 'nativePrompt',
                    },
                ],
            },
            {
                name: 'reports errors for window calls to dialog APIs',
                code: `
          window.alert('Attention');
          window['confirm']('Are you sure?');
          window.prompt('Enter your name:');

        `,
                errors: [
                    {
                        messageId: 'nativeAlert',
                    },
                    {
                        messageId: 'nativeConfirm',
                    },
                    {
                        messageId: 'nativePrompt',
                    },
                ],
            },
            {
                name: 'reports errors for globalThis calls to dialog APIs',
                code: `
          globalThis['alert']('Attention');
          globalThis.confirm('Are you sure?');
          globalThis['prompt']('Enter your name:');
        `,
                errors: [
                    {
                        messageId: 'nativeAlert',
                    },
                    {
                        messageId: 'nativeConfirm',
                    },
                    {
                        messageId: 'nativePrompt',
                    },
                ],
            },
            {
                name: 'reports errors for self calls to dialog APIs',
                code: `
          self.alert('Attention');
          self['confirm']('Are you sure?');
          self.prompt('Enter your name:');
        `,
                errors: [
                    {
                        messageId: 'nativeAlert',
                    },
                    {
                        messageId: 'nativeConfirm',
                    },
                    {
                        messageId: 'nativePrompt',
                    },
                ],
            },
            {
                name: 'reports error in React component with JSX',
                code: `
          import { Text } from '@hubspot/ui-extensions';
          function Component() {
            alert('Error');
            return <Text>Hello</Text>;
          }
        `,
                errors: [{ messageId: 'nativeAlert' }],
            },
            {
                name: 'reports error in async, arrow, and class method contexts',
                code: `
          async function test1() { alert('async'); }
          const test2 = () => confirm('arrow');
          class Test { method() { prompt('class'); } }
        `,
                errors: [
                    { messageId: 'nativeAlert' },
                    { messageId: 'nativeConfirm' },
                    { messageId: 'nativePrompt' },
                ],
            },
            {
                name: 'reports error in try/catch and nested scopes',
                code: `
          try { alert('error'); } catch (e) { confirm('caught'); }
          function outer() { function inner() { prompt('nested'); } }
        `,
                errors: [
                    { messageId: 'nativeAlert' },
                    { messageId: 'nativeConfirm' },
                    { messageId: 'nativePrompt' },
                ],
            },
        ],
    });
    // TypeScript-specific tests (requires TypeScript parser)
    tsRuleTester.run('no-browser-dialogs (TypeScript)', noBrowserDialogs, {
        valid: [
            {
                name: 'allows dialog types in type alias',
                code: `
          type AlertType = typeof alert;
          type ConfirmType = typeof confirm;
          type PromptType = typeof prompt;
        `,
            },
            {
                name: 'allows dialog types in interface property',
                code: `
          interface TestClient {
            alert: typeof alert;
            confirm: typeof confirm;
            prompt: typeof prompt;
          }
        `,
            },
            {
                name: 'allows dialog types in function return type',
                code: `
          function getRequestFn(): typeof alert {
            return action.addAlert;
          }

          function getConfirmFn(): typeof confirm {
            return action.addConfirm;
          }

          function getPromptFn(): typeof prompt {
            return action.addPrompt;
          }
        `,
            },
        ],
        invalid: [
            {
                name: 'reports error for dialog calls even after type declarations',
                code: `
          type AlertType = typeof alert;
          type ConfirmType = typeof confirm;
          type PromptType = typeof prompt;

          function getData() {
            alert('Attention');
            confirm('Are you sure?');
            prompt('Enter your name:');
          }
        `,
                errors: [
                    {
                        messageId: 'nativeAlert',
                    },
                    {
                        messageId: 'nativeConfirm',
                    },
                    {
                        messageId: 'nativePrompt',
                    },
                ],
            },
        ],
    });
});
